#include "controller.h"

#include <stdbool.h>
#include <stdint.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static void controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    /* If either sensor is stale for more than 1000ms, go to safe all-off state */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return;
    }

    bool turb_stale = (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
    bool level_stale = (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;

    if (turb_stale || level_stale) {
        controller_set_safe_idle(controller);
    }
}

static void controller_enter_filtering(controller_t *controller, uint32_t now_ms)
{
    /* FILTERING: filter on, drain closed */
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

static void controller_enter_settling(controller_t *controller, uint32_t now_ms)
{
    /* SETTLING: filter off, drain closed, waiting settle timer */
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = now_ms;
}

static void controller_enter_draining(controller_t *controller)
{
    /* DRAINING: drain open */
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

static void controller_enter_complete(controller_t *controller)
{
    /* COMPLETE: level below minimum, filter off, drain closed */
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle timeout/malformed input first - go to safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) ||
                         (previous_drain_open != controller->drain_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Handle idle input - no state change, but check timeout */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        controller_check_sensor_timeout(controller, input.now_ms);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) ||
                         (previous_drain_open != controller->drain_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Update sensor validity and timestamps */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check for sensor timeout */
        if (!controller->has_valid_level || (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_idle(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check LEVEL < 15 condition - stay in COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller_enter_complete(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check for clear streak reset */
        if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* TURB > 35: reset clear streak, stay in current state or transition to FILTERING */
            controller->clear_streak_count = 0;

            /* If we were in SETTLING and got a disturbance (TURB > 40), return to FILTERING */
            if (controller->state == CONTROLLER_STATE_SETTLING && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                controller_enter_filtering(controller, input.now_ms);
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

            /* If we were in SAFE_IDLE with both sensors valid and LEVEL >= 40, start FILTERING */
            if (controller->state == CONTROLLER_STATE_SAFE_IDLE && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller_enter_filtering(controller, input.now_ms);
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

            /* In FILTERING, just reset streak and stay in FILTERING */
            if (controller->state == CONTROLLER_STATE_FILTERING) {
                /* Nothing to do - already in FILTERING with filter on */
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

            /* In DRAINING, if TURB > 50 and LEVEL >= 40, close drain, turn filter on, reset streak */
            if (controller->state == CONTROLLER_STATE_DRAINING && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
                    controller->clear_streak_count = 0;
                    controller_enter_filtering(controller, input.now_ms);
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = controller->state;
                    output.state_name = controller_state_name(controller->state);
                    output.changed = (previous_filter_on != controller->filter_on) ||
                                     (previous_drain_open != controller->drain_open) ||
                                     (previous_state != controller->state);
                    return output;
                }
            }

            /* In DRAINING with no disturbance, just reset streak and stay in DRAINING */
            if (controller->state == CONTROLLER_STATE_DRAINING) {
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

            /* In COMPLETE, stay in COMPLETE */
            if (controller->state == CONTROLLER_STATE_COMPLETE) {
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

        } else {
            /* TURB <= 35: increment clear streak */
            if (controller->clear_streak_count < CONTROLLER_CLEAR_STREAK_REQUIRED - 1) {
                controller->clear_streak_count++;
            }

            /* Check if we should enter SETTLING */
            if (controller->state == CONTROLLER_STATE_SAFE_IDLE && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller_enter_settling(controller, input.now_ms);
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

            /* Check if we should enter SETTLING from FILTERING */
            if (controller->state == CONTROLLER_STATE_FILTERING && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED - 1) {
                    controller_enter_settling(controller, input.now_ms);
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = controller->state;
                    output.state_name = controller_state_name(controller->state);
                    output.changed = (previous_filter_on != controller->filter_on) ||
                                     (previous_drain_open != controller->drain_open) ||
                                     (previous_state != controller->state);
                    return output;
                }
            }

            /* Check if we should enter DRAINING from SETTLING */
            if (controller->state == CONTROLLER_STATE_SETTLING && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                uint32_t settle_elapsed_ms = input.now_ms - controller->settling_started_ms;
                if (settle_elapsed_ms >= CONTROLLER_SETTLING_MS) {
                    /* Check if latest TURB <= 35 */
                    if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                        controller_enter_draining(controller);
                        output.filter_on = controller->filter_on;
                        output.drain_open = controller->drain_open;
                        output.state = controller->state;
                        output.state_name = controller_state_name(controller->state);
                        output.changed = (previous_filter_on != controller->filter_on) ||
                                         (previous_drain_open != controller->drain_open) ||
                                         (previous_state != controller->state);
                        return output;
                    }
                }
            }

            /* In DRAINING, stay in DRAINING */
            if (controller->state == CONTROLLER_STATE_DRAINING) {
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }

            /* In COMPLETE, stay in COMPLETE */
            if (controller->state == CONTROLLER_STATE_COMPLETE) {
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_filter_on != controller->filter_on) ||
                                 (previous_drain_open != controller->drain_open) ||
                                 (previous_state != controller->state);
                return output;
            }
        }

    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check for sensor timeout */
        if (!controller->has_valid_turbidity || (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_idle(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check LEVEL < 15 condition - stay in COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller_enter_complete(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter FILTERING */
        if (controller->state == CONTROLLER_STATE_SAFE_IDLE && controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter FILTERING from SETTLING (disturbance during settle) */
        if (controller->state == CONTROLLER_STATE_SETTLING && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter DRAINING from SETTLING */
        if (controller->state == CONTROLLER_STATE_SETTLING && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            uint32_t settle_elapsed_ms = input.now_ms - controller->settling_started_ms;
            if (settle_elapsed_ms >= CONTROLLER_SETTLING_MS) {
                /* Check if latest TURB <= 35 */
                if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_enter_draining(controller);
                    output.filter_on = controller->filter_on;
                    output.drain_open = controller->drain_open;
                    output.state = controller->state;
                    output.state_name = controller_state_name(controller->state);
                    output.changed = (previous_filter_on != controller->filter_on) ||
                                     (previous_drain_open != controller->drain_open) ||
                                     (previous_state != controller->state);
                    return output;
                }
            }
        }

        /* In DRAINING, stay in DRAINING */
        if (controller->state == CONTROLLER_STATE_DRAINING) {
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* In COMPLETE, stay in COMPLETE */
        if (controller->state == CONTROLLER_STATE_COMPLETE) {
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

    }

    /* Default case - should not reach here, but handle safely */
    controller_set_safe_idle(controller);
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                     (previous_drain_open != controller->drain_open) ||
                     (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#include "controller.h"

#include <stdbool.h>
#include <stdint.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool controller_should_enter_filtering(controller_t *controller, int turbidity_ntu, int level)
{
    /* Enter FILTERING when: both sensors valid, TURB > 35, LEVEL >= 40 */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return false;
    }
    if (turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
        return false;
    }
    if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
        return false;
    }
    return true;
}

static bool controller_should_enter_settling(controller_t *controller, int turbidity_ntu, int level)
{
    /* Enter SETTLING when: both sensors valid, clear streak = 3, LEVEL >= 40 */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return false;
    }
    if (turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
        return false;
    }
    if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
        return false;
    }
    if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED - 1) {
        return true;
    }
    return false;
}

static bool controller_should_enter_draining(controller_t *controller, int turbidity_ntu, int level, uint32_t now_ms)
{
    /* Enter DRAINING when: in SETTLING, settle timer elapsed, latest TURB <= 35, LEVEL >= 40 */
    if (controller->state != CONTROLLER_STATE_SETTLING) {
        return false;
    }
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return false;
    }
    if (turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
        return false;
    }
    if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
        return false;
    }
    uint32_t settle_elapsed_ms = now_ms - controller->settling_started_ms;
    if (settle_elapsed_ms >= CONTROLLER_SETTLING_MS) {
        return true;
    }
    return false;
}

static bool controller_should_enter_complete(controller_t *controller, int level)
{
    /* Enter COMPLETE when: LEVEL < 15 */
    if (!controller->has_valid_level) {
        return false;
    }
    return (level < CONTROLLER_COMPLETE_LEVEL);
}

static void controller_handle_disturbance_during_settling(controller_t *controller, int turbidity_ntu)
{
    /* During SETTLING, if TURB > 40, reset streak and return to FILTERING */
    if (controller->state == CONTROLLER_STATE_SETTLING && turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
        controller_set_safe_idle(controller);
        controller->has_valid_turbidity = true;
        controller->has_valid_level = true;
        controller->clear_streak_count = 0;
    }
}

static void controller_handle_disturbance_during_draining(controller_t *controller, int turbidity_ntu, int level)
{
    /* During DRAINING, if TURB > 50 and LEVEL >= 40, close drain, turn filter on, reset streak */
    if (controller->state == CONTROLLER_STATE_DRAINING && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        if (turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
            controller_set_safe_idle(controller);
            controller->has_valid_turbidity = true;
            controller->has_valid_level = true;
            controller->clear_streak_count = 0;
        }
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle timeout/malformed input - go to safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) ||
                         (previous_drain_open != controller->drain_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Handle idle input - check for sensor timeout */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        /* Check if either sensor is stale */
        bool turb_stale = (!controller->has_valid_turbidity ||
                          (controller->has_valid_turbidity && (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS));
        bool level_stale = (!controller->has_valid_level ||
                           (controller->has_valid_level && (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS));

        if (turb_stale || level_stale) {
            controller_set_safe_idle(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* No stale sensors, just update timestamps if we have valid data */
        if (controller->has_valid_turbidity) {
            controller->last_turbidity_ms = input.now_ms;
        }
        if (controller->has_valid_level) {
            controller->last_level_ms = input.now_ms;
        }

        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) ||
                         (previous_drain_open != controller->drain_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Update sensor validity and timestamps */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check LEVEL < 15 condition first */
        if (controller_should_enter_complete(controller, controller->last_level)) {
            controller_enter_complete(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Handle disturbance during SETTLING */
        if (controller_handle_disturbance_during_settling(controller, input.turbidity_ntu)) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Handle disturbance during DRAINING */
        if (controller_handle_disturbance_during_draining(controller, input.turbidity_ntu, controller->last_level)) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter COMPLETE */
        if (controller_should_enter_complete(controller, controller->last_level)) {
            controller_enter_complete(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter FILTERING */
        if (controller_should_enter_filtering(controller, input.turbidity_ntu, controller->last_level)) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter SETTLING */
        if (controller_should_enter_settling(controller, input.turbidity_ntu, controller->last_level)) {
            controller_enter_settling(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter DRAINING from SETTLING */
        if (controller_should_enter_draining(controller, input.turbidity_ntu, controller->last_level, input.now_ms)) {
            controller_enter_draining(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Update clear streak for non-disturbance inputs */
        if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            if (controller->clear_streak_count < CONTROLLER_CLEAR_STREAK_REQUIRED - 1) {
                controller->clear_streak_count++;
            }
        } else {
            /* TURB > 35: reset clear streak */
            controller->clear_streak_count = 0;
        }

    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check LEVEL < 15 condition */
        if (controller_should_enter_complete(controller, controller->last_level)) {
            controller_enter_complete(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Handle disturbance during SETTLING */
        if (controller_handle_disturbance_during_settling(controller, controller->last_turbidity_ntu)) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Handle disturbance during DRAINING */
        if (controller_handle_disturbance_during_draining(controller, controller->last_turbidity_ntu, input.level)) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter COMPLETE */
        if (controller_should_enter_complete(controller, controller->last_level)) {
            controller_enter_complete(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter FILTERING */
        if (controller_should_enter_filtering(controller, controller->last_turbidity_ntu, input.level)) {
            controller_enter_filtering(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter SETTLING */
        if (controller_should_enter_settling(controller, controller->last_turbidity_ntu, input.level)) {
            controller_enter_settling(controller, input.now_ms);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

        /* Check if we should enter DRAINING from SETTLING */
        if (controller_should_enter_draining(controller, controller->last_turbidity_ntu, input.level, input.now_ms)) {
            controller_enter_draining(controller);
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_filter_on != controller->filter_on) ||
                             (previous_drain_open != controller->drain_open) ||
                             (previous_state != controller->state);
            return output;
        }

    }

    /* Default case - no change */
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                     (previous_drain_open != controller->drain_open) ||
                     (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

